for (const [language, additions] of Object.entries(translations)) {
  const filePath = path.join(localesDir, language, 'translation.json');
  const existing = JSON.parse(await readFile(filePath, 'utf8'));
  const merged = { ...existing, ...additions, ...(extraTranslations[language] || {}), ...(finalBackfill[language] || {}) };
  const sorted = Object.fromEntries(Object.entries(merged).sort(([a], [b]) => a.localeCompare(b)));
  await writeFile(filePath, `${JSON.stringify(sorted, null, 2)}\n`, 'utf8');
}

console.log('Merged public landing translations.');
